#include <algorithm>
#include <iostream>
#include <string>
using namespace std;

struct Student {
    string name;
    int score;
};

bool cmp(Student a, Student b) {
    return a.score > b.score;
}

int main() {
    Student a[3] = {{"Ann", 90}, {"Bob", 85}, {"Cindy", 98}};
    sort(a, a + 3, cmp);
    for (int i = 0; i < 3; i++) {
        cout << a[i].name << " " << a[i].score << endl;
    }
    return 0;
}

