#include <algorithm>
#include <iostream>
#include <string>
#include <vector>
using namespace std;

struct Student {
    string name;
    int score;
};

bool cmp(Student a, Student b) {
    if (a.score != b.score) return a.score > b.score;
    return a.name < b.name;
}

int main() {
    vector<Student> a = {{"Bob", 90}, {"Ann", 90}, {"Cindy", 95}};
    sort(a.begin(), a.end(), cmp);
    for (auto s : a) cout << s.name << " " << s.score << endl;
    return 0;
}

